from functools import reduce

N = int(input())
G = int(input())

users = [input().strip().split() for i in range(N)]

def calculate_average(steps):
    return sum(steps) / len(steps)

def exceeds_goal(user):
    name = user[0]
    steps = list(map(int, user[1:]))
    avg_steps = calculate_average(steps)
    return avg_steps >= G, name, max(steps)

valid_users = []
total_steps = 0

for user in users:
    meets_goal, name, personal_best = exceeds_goal(user)
    if meets_goal:
        valid_users.append(name)
        total_steps += personal_best

print(valid_users, total_steps)
